from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import os
import pickle

app = Flask(__name__)

# Load and encode employee photos
def load_and_encode_images(image_folder):
    known_face_encodings = []
    known_face_names = []
    for filename in os.listdir(image_folder):
        if filename.endswith(".jpg") or filename.endswith(".png"):
            image_path = os.path.join(image_folder, filename)
            image = face_recognition.load_image_file(image_path)
            encoding = face_recognition.face_encodings(image)[0]
            known_face_encodings.append(encoding)
            known_face_names.append(os.path.splitext(filename)[0])
    return known_face_encodings, known_face_names

# Train model on employee photos
def train_model(image_folder='employee_photos'):
    known_face_encodings, known_face_names = load_and_encode_images(image_folder)
    with open('trained_model.pkl', 'wb') as f:
        pickle.dump((known_face_encodings, known_face_names), f)

# Load trained model
def load_trained_model():
    with open('trained_model.pkl', 'rb') as f:
        return pickle.load(f)

# Secure prediction function
def secure_predict(face_encodings, known_face_encodings, known_face_names):
    probabilities = []
    for face_encoding in face_encodings:
        distances = face_recognition.face_distance(known_face_encodings, face_encoding)
        scores = 1 - distances
        total_score = np.sum(scores)
        probabilities.append({name: score / total_score for name, score in zip(known_face_names, scores)})
    return probabilities

@app.route('/recognize', methods=['POST'])
def recognize_faces():
    if 'image' not in request.files:
        return jsonify({"error": "No image provided"}), 400

    file = request.files['image']
    image = face_recognition.load_image_file(file)
    face_encodings = face_recognition.face_encodings(image)

    if not face_encodings:
        return jsonify({"error": "No faces found in the image"}), 400

    known_face_encodings, known_face_names = load_trained_model()
    probabilities = secure_predict(face_encodings, known_face_encodings, known_face_names)

    return jsonify(probabilities)

if __name__ == '__main__':
    train_model()
    app.run(host='0.0.0.0', port=5000)